namespace sv_91630b7e27224c51b228eaa04cb79c3b.Services;

public record Channel(int Id, string Name, string Description, int UnreadCount);
public record Message(int Id, int ChannelId, string Author, string Content, DateTime SentAt, int? ReplyToId, List<Reaction> Reactions);
public record Reaction(string Emoji, List<string> Users);
public record ThreadSummary(int RootMessageId, int ReplyCount, DateTime LastReplyAt);

public interface IChatService
{
    Task<List<Channel>> GetChannelsAsync();
    Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take);
    Task<Message> SendMessageAsync(int channelId, string content, int? replyToId);
    Task<List<Message>> GetThreadAsync(int rootMessageId);
    Task AddReactionAsync(int messageId, string emoji);
    Task MarkChannelReadAsync(int channelId);
}

@using sv_91630b7e27224c51b228eaa04cb79c3b.Services

<div class="channel-item @(IsActive ? "active" : "")" @onclick="OnClick">
    <div class="channel-header">
        <span class="channel-name"># @Channel.Name</span>
        @if (Channel.UnreadCount > 0)
        {
            <span class="unread-badge">@Channel.UnreadCount</span>
        }
    </div>
    <div class="channel-desc">@TruncatedDescription</div>
</div>

@code {
    [Parameter, EditorRequired] public Channel Channel { get; set; } = default!;
    [Parameter] public bool IsActive { get; set; }
    [Parameter] public EventCallback<Channel> OnSelected { get; set; }

    private string TruncatedDescription =>
        Channel.Description.Length > 40
            ? Channel.Description[..40] + "…"
            : Channel.Description;

    private async Task OnClick() => await OnSelected.InvokeAsync(Channel);
}

.channel-item {
    padding: 8px 12px;
    cursor: pointer;
    border-radius: 6px;
    margin: 2px 6px;
    transition: background-color 0.15s;
}

.channel-item:hover {
    background-color: rgba(255, 255, 255, 0.08);
}

.channel-item.active {
    background-color: rgba(255, 255, 255, 0.15);
}

.channel-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
}

.channel-name {
    font-weight: 600;
    font-size: 0.95rem;
    color: #e0e0e0;
}

.channel-item.active .channel-name {
    color: #fff;
}

.unread-badge {
    background-color: #e74c3c;
    color: #fff;
    font-size: 0.7rem;
    font-weight: 700;
    padding: 1px 6px;
    border-radius: 10px;
    min-width: 18px;
    text-align: center;
}

.channel-desc {
    font-size: 0.78rem;
    color: #999;
    margin-top: 2px;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

@using sv_91630b7e27224c51b228eaa04cb79c3b.Services

<div class="reaction-bar">
    @foreach (var reaction in Reactions)
    {
        <button class="reaction-badge" @onclick="() => OnReactionClicked.InvokeAsync(reaction.Emoji)"
                title="@string.Join(", ", reaction.Users)">
            @reaction.Emoji @reaction.Users.Count
        </button>
    }
</div>

@code {
    [Parameter, EditorRequired] public List<Reaction> Reactions { get; set; } = [];
    [Parameter] public EventCallback<string> OnReactionClicked { get; set; }
}

.reaction-bar {
    display: flex;
    flex-wrap: wrap;
    gap: 4px;
    margin-top: 4px;
}

.reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 3px;
    background: #f0f0f0;
    border: 1px solid #ddd;
    border-radius: 12px;
    padding: 2px 8px;
    font-size: 0.8rem;
    cursor: pointer;
    transition: background 0.15s;
}

.reaction-badge:hover {
    background: #e0e0ff;
    border-color: #aaf;
}

.emoji-picker {
    display: flex;
    gap: 2px;
    background: #fff;
    border: 1px solid #ddd;
    border-radius: 8px;
    padding: 4px 6px;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.15);
    position: absolute;
    bottom: 100%;
    right: 0;
    margin-bottom: 4px;
    z-index: 10;
}

.emoji-btn {
    background: none;
    border: none;
    font-size: 1.2rem;
    cursor: pointer;
    padding: 2px 4px;
    border-radius: 4px;
    transition: background 0.15s;
}

.emoji-btn:hover {
    background: #f0f0f0;
}

.message-input {
    display: flex;
    gap: 8px;
    padding: 12px 16px;
    border-top: 1px solid #e0e0e0;
    background: #fff;
    align-items: flex-end;
}

.message-input textarea {
    flex: 1;
    resize: none;
    border: 1px solid #ddd;
    border-radius: 8px;
    padding: 8px 12px;
    font-size: 0.9rem;
    font-family: inherit;
    outline: none;
    transition: border-color 0.15s;
}

.message-input textarea:focus {
    border-color: #5865f2;
}

.send-btn {
    background: #5865f2;
    color: #fff;
    border: none;
    border-radius: 8px;
    padding: 8px 16px;
    font-weight: 600;
    cursor: pointer;
    transition: background 0.15s;
    white-space: nowrap;
}

.send-btn:hover:not(:disabled) {
    background: #4752c4;
}

.send-btn:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}

