@using sv_91630b7e27224c51b228eaa04cb79c3b.Services

<div class="message-bubble" @onmouseenter="() => showActions = true" @onmouseleave="HideActions">
    <div class="msg-header">
        <span class="msg-author">@Message.Author</span>
        <span class="msg-time" title="@Message.SentAt.ToString("g")">@FormatRelativeTime(Message.SentAt)</span>
    </div>
    <div class="msg-content">@Message.Content</div>

    @if (Message.Reactions.Count > 0)
    {
        <ReactionBar Reactions="Message.Reactions" OnReactionClicked="HandleReaction" />
    }

    @if (ThreadReplyCount > 0)
    {
        <button class="thread-link" @onclick="() => OnOpenThread.InvokeAsync(Message.Id)">
            @ThreadReplyCount @(ThreadReplyCount == 1 ? "reply" : "replies")
        </button>
    }

    @if (showActions)
    {
        <div class="msg-actions">
            <button class="action-btn" @onclick="() => OnOpenThread.InvokeAsync(Message.Id)" title="Reply in thread">
                💬 Reply
            </button>
            <div class="react-wrapper">
                <button class="action-btn" @onclick="ToggleEmojiPicker" title="Add reaction">
                    😀 React
                </button>
                @if (showEmojiPicker)
                {
                    <EmojiPicker OnEmojiSelected="HandleEmojiSelected" />
                }
            </div>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired] public Message Message { get; set; } = default!;
    [Parameter] public int ThreadReplyCount { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }

    private bool showActions;
    private bool showEmojiPicker;

    private void HideActions()
    {
        showActions = false;
        showEmojiPicker = false;
    }

    private void ToggleEmojiPicker() => showEmojiPicker = !showEmojiPicker;

    private async Task HandleEmojiSelected(string emoji)
    {
        showEmojiPicker = false;
        await OnReact.InvokeAsync((Message.Id, emoji));
    }

    private async Task HandleReaction(string emoji)
    {
        await OnReact.InvokeAsync((Message.Id, emoji));
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.Now - sentAt;
        if (diff.TotalMinutes < 1) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d");
    }
}

.message-bubble {
    padding: 8px 16px;
    position: relative;
    border-radius: 4px;
    transition: background 0.1s;
}

.message-bubble:hover {
    background: #f8f8f8;
}

.msg-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.msg-author {
    font-weight: 700;
    font-size: 0.95rem;
    color: #1a1a2e;
}

.msg-time {
    font-size: 0.75rem;
    color: #999;
}

.msg-content {
    font-size: 0.92rem;
    line-height: 1.4;
    color: #2c2c2c;
    white-space: pre-wrap;
    word-break: break-word;
}

.thread-link {
    background: none;
    border: none;
    color: #5865f2;
    font-size: 0.8rem;
    font-weight: 600;
    cursor: pointer;
    padding: 2px 0;
    margin-top: 4px;
}

.thread-link:hover {
    text-decoration: underline;
}

.msg-actions {
    position: absolute;
    top: -12px;
    right: 12px;
    display: flex;
    gap: 2px;
    background: #fff;
    border: 1px solid #ddd;
    border-radius: 6px;
    padding: 2px 4px;
    box-shadow: 0 1px 4px rgba(0, 0, 0, 0.1);
    z-index: 5;
}

.action-btn {
    background: none;
    border: none;
    font-size: 0.8rem;
    cursor: pointer;
    padding: 4px 8px;
    border-radius: 4px;
    white-space: nowrap;
    transition: background 0.15s;
}

.action-btn:hover {
    background: #f0f0f0;
}

.react-wrapper {
    position: relative;
}

