.message-bubble {
    padding: 8px 16px;
    position: relative;
    border-radius: 4px;
    transition: background 0.1s;
}

.message-bubble:hover {
    background: #f8f8f8;
}

.msg-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.msg-author {
    font-weight: 700;
    font-size: 0.95rem;
    color: #1a1a2e;
}

