    color: #2c2c2c;
    white-space: pre-wrap;
    word-break: break-word;
}

.thread-link {
    background: none;
    border: none;
    color: #5865f2;
    font-size: 0.8rem;
    font-weight: 600;
    cursor: pointer;
    padding: 2px 0;
    margin-top: 4px;
}

.thread-link:hover {
    text-decoration: underline;
}

.msg-actions {
    position: absolute;
    top: -12px;
    right: 12px;
    display: flex;
    gap: 2px;
    background: #fff;
    border: 1px solid #ddd;
    border-radius: 6px;
    padding: 2px 4px;
    box-shadow: 0 1px 4px rgba(0, 0, 0, 0.1);
