    background: none;
    border: none;
    font-size: 0.8rem;
    cursor: pointer;
    padding: 4px 8px;
    border-radius: 4px;
    white-space: nowrap;
    transition: background 0.15s;
}

.action-btn:hover {
    background: #f0f0f0;
}

.react-wrapper {
    position: relative;
}

