toolArgs.file_text:
@using sv_91630b7e27224c51b228eaa04cb79c3b.Services
@inject IJSRuntime JS

<div class="message-list" @ref="scrollContainer">
    @if (IsLoadingOlder)
    {
        <div class="loading-indicator">Loading older messages…</div>
    }
    @if (HasMoreMessages)
    {
        <button class="load-more-btn" @onclick="OnLoadMore" disabled="@IsLoadingOlder">
            ↑ Load older messages
        </button>
    }
    @foreach (var msg in Messages)
    {
        <MessageBubble Message="msg"
                       ThreadReplyCount="GetThreadReplyCount(msg.Id)"
                       OnOpenThread="OnOpenThread"
                       OnReact="OnReact" />
    }
    <div @ref="bottomAnchor"></div>
</div>

@code {
    [Parameter, EditorRequired] public List<Message> Messages { get; set; } = [];
    [Parameter] public Dictionary<int, ThreadSummary> ThreadSummaries { get; set; } = [];
    [Parameter] public bool HasMoreMessages { get; set; }
    [Parameter] public bool IsLoadingOlder { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }

    private ElementReference scrollContainer;
    private ElementReference bottomAnchor;
    private int lastMessageCount;

    private int GetThreadReplyCount(int messageId)
    {
        return ThreadSummaries.TryGetValue(messageId, out var summary) ? summary.ReplyCount : 0;
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        // Auto-scroll to bottom when new messages arrive
        if (Messages.Count > lastMessageCount && Messages.Count > 0)
        {
            lastMessageCount = Messages.Count;
            try
            {
                await JS.InvokeVoidAsync("eval", "document.querySelector('[data-bottom-anchor]')?.scrollIntoView()");
            }
            catch (JSDisconnectedException) { }
        }
    }
}

