.thread-panel {
    display: flex;
    flex-direction: column;
    height: 100%;
    background: #fafafa;
    border-left: 1px solid #e0e0e0;
    overflow: hidden;
}

.thread-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 12px 16px;
    border-bottom: 1px solid #e0e0e0;
    flex-shrink: 0;
