@code {
    private List<Channel> channels = [];
    private Channel? activeChannel;
    private List<Message> messages = [];
    private Dictionary<int, ThreadSummary> threadSummaries = [];
    private bool hasMoreMessages;
    private bool isLoadingOlder;
    private const int PageSize = 30;

    // Thread state
    private bool threadOpen;
    private Message? threadRootMessage;
    private List<Message> threadReplies = [];
    private bool isLoadingThread;

    protected override async Task OnInitializedAsync()
    {
        channels = await ChatService.GetChannelsAsync();
        if (channels.Count > 0)
        {
            await SelectChannel(channels[0]);
        }
    }

    private async Task SelectChannel(Channel channel)
    {
        activeChannel = channel;
        messages = [];
        threadSummaries = [];
        CloseThreadSync();

        var loaded = await ChatService.GetMessagesAsync(channel.Id, 0, PageSize);
        messages = loaded;
        hasMoreMessages = loaded.Count >= PageSize;
        BuildThreadSummaries();

        await ChatService.MarkChannelReadAsync(channel.Id);

        // Update unread count locally
        var idx = channels.FindIndex(c => c.Id == channel.Id);
        if (idx >= 0)
        {
            channels[idx] = channel with { UnreadCount = 0 };
        }
    }

    private async Task LoadOlderMessages()
    {
        if (activeChannel is null || isLoadingOlder) return;

        isLoadingOlder = true;
        var older = await ChatService.GetMessagesAsync(activeChannel.Id, messages.Count, PageSize);
        hasMoreMessages = older.Count >= PageSize;

        // Prepend older messages
        messages = [.. older, .. messages];
        BuildThreadSummaries();
        isLoadingOlder = false;
    }

    private async Task SendMessage(string content)
    {
        if (activeChannel is null) return;
        var msg = await ChatService.SendMessageAsync(activeChannel.Id, content, null);
        messages.Add(msg);
    }

    private async Task HandleReaction((int MessageId, string Emoji) args)
    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);

        // Optimistically update local state
        UpdateReactionLocally(messages, args.MessageId, args.Emoji);
        if (threadReplies.Count > 0)
        {
            UpdateReactionLocally(threadReplies, args.MessageId, args.Emoji);
        }
    }

    private static void UpdateReactionLocally(List<Message> msgList, int messageId, string emoji)
    {
        var idx = msgList.FindIndex(m => m.Id == messageId);
        if (idx < 0) return;

        var msg = msgList[idx];
        var reactions = msg.Reactions.ToList();
        var existing = reactions.FindIndex(r => r.Emoji == emoji);
        if (existing >= 0)
        {
            var r = reactions[existing];
            reactions[existing] = r with { Users = [.. r.Users, "You"] };
        }
        else
        {
            reactions.Add(new Reaction(emoji, ["You"]));
        }
        msgList[idx] = msg with { Reactions = reactions };
    }

    private async Task OpenThread(int rootMessageId)
    {
        isLoadingThread = true;
        threadOpen = true;
        threadRootMessage = messages.FirstOrDefault(m => m.Id == rootMessageId);
        threadReplies = [];

        var replies = await ChatService.GetThreadAsync(rootMessageId);
        threadReplies = replies;
        isLoadingThread = false;
    }

    private void CloseThread()
    {
        CloseThreadSync();
    }

    private void CloseThreadSync()
    {
        threadOpen = false;
        threadRootMessage = null;
        threadReplies = [];
    }

    private async Task SendThreadReply(string content)
    {
        if (activeChannel is null || threadRootMessage is null) return;

        var reply = await ChatService.SendMessageAsync(activeChannel.Id, content, threadRootMessage.Id);
        threadReplies.Add(reply);

        // Update thread summary count
        if (threadSummaries.TryGetValue(threadRootMessage.Id, out var summary))
        {
            threadSummaries[threadRootMessage.Id] = summary with
            {
                ReplyCount = summary.ReplyCount + 1,
                LastReplyAt = reply.SentAt
            };
        }
        else
        {
            threadSummaries[threadRootMessage.Id] = new ThreadSummary(threadRootMessage.Id, 1, reply.SentAt);
        }
    }

    private void BuildThreadSummaries()
    {
        threadSummaries = [];
        foreach (var msg in messages.Where(m => m.ReplyToId is not null))
        {
            var rootId = msg.ReplyToId!.Value;
            if (threadSummaries.TryGetValue(rootId, out var existing))
            {
                threadSummaries[rootId] = existing with
                {
                    ReplyCount = existing.ReplyCount + 1,
                    LastReplyAt = msg.SentAt > existing.LastReplyAt ? msg.SentAt : existing.LastReplyAt
                };
            }
            else
            {
                threadSummaries[rootId] = new ThreadSummary(rootId, 1, msg.SentAt);
            }
        }
    }
}

